def range_summary(nums):
    if not nums:  # Handle empty list edge case
        return ''

    distinct_nums = sorted(set(nums))
    ranges = []

    current_range = [distinct_nums[0]]

    for num in distinct_nums[1:]:
        if num == current_range[-1] + 1:
            current_range.append(num)
        else:
            if len(current_range) > 1:
                ranges.append(f"{current_range[0]}-{current_range[-1]}" if current_range[0] != current_range[-1] else f"{current_range[0]}")
            else:
                ranges.append(str(current_range[0]))
            current_range = [num]

    if len(current_range) > 1:
        ranges.append(f"{current_range[0]}-{current_range[-1]}" if current_range[0] != current_range[-1] else f"{current_range[0]}")
    else:
        ranges.append(str(current_range[0]))

    return ','.join(ranges)
